import pytest

class TestDeregisterHook:
    class MockClass:
        def __init__(self):
            self.hooks = {
                'event1': ['hook1', 'hook2'],
                'event2': ['hook3']
            }

        def deregister_hook(self, event, hook):
            try:
                self.hooks[event].remove(hook)
                return True
            except ValueError:
                return False

    def setup_method(self):
        self.mock = self.MockClass()

    def test_deregister_existing_hook(self):
        result = self.mock.deregister_hook('event1', 'hook1')
        assert result is True
        assert 'hook1' not in self.mock.hooks['event1']

    def test_deregister_non_existing_hook(self):
        result = self.mock.deregister_hook('event1', 'hook3')
        assert result is False
        assert 'hook1' in self.mock.hooks['event1']
        assert 'hook2' in self.mock.hooks['event1']

    def test_deregister_hook_from_empty_event(self):
        result = self.mock.deregister_hook('event2', 'hook4')
        assert result is False
        assert 'hook3' in self.mock.hooks['event2']

    def test_deregister_hook_from_non_existing_event(self):
        result = self.mock.deregister_hook('event3', 'hook1')
        assert result is False

    def test_deregister_hook_multiple_times(self):
        self.mock.deregister_hook('event1', 'hook1')
        result = self.mock.deregister_hook('event1', 'hook1')
        assert result is False

    def test_deregister_hook_case_sensitivity(self):
        self.mock.hooks['event1'].append('Hook1')
        result = self.mock.deregister_hook('event1', 'hook1')
        assert result is False
        assert 'Hook1' in self.mock.hooks['event1']

    def test_deregister_hook_with_none(self):
        result = self.mock.deregister_hook('event1', None)
        assert result is False
        assert 'hook1' in self.mock.hooks['event1']
        assert 'hook2' in self.mock.hooks['event1']

    def test_deregister_hook_with_empty_string(self):
        self.mock.hooks['event1'].append('')
        result = self.mock.deregister_hook('event1', '')
        assert result is True
        assert '' not in self.mock.hooks['event1']

    def test_deregister_hook_with_non_string(self):
        self.mock.hooks['event1'].append(123)
        result = self.mock.deregister_hook('event1', 123)
        assert result is True
        assert 123 not in self.mock.hooks['event1']

