import pytest
from collections import OrderedDict

def from_key_val_list(value):
    if value is None:
        return None

    if isinstance(value, (str, bytes, bool, int)):
        raise ValueError("cannot encode objects that are not 2-tuples")

    return OrderedDict(value)

def test_from_key_val_list_with_valid_list_of_tuples():
    assert from_key_val_list([('key1', 'val1'), ('key2', 'val2')]) == OrderedDict([('key1', 'val1'), ('key2', 'val2')])

def test_from_key_val_list_with_single_tuple():
    assert from_key_val_list([('key', 'val')]) == OrderedDict([('key', 'val')])

def test_from_key_val_list_with_empty_list():
    assert from_key_val_list([]) == OrderedDict()

def test_from_key_val_list_with_dict():
    assert from_key_val_list({'key': 'val'}) == OrderedDict([('key', 'val')])

def test_from_key_val_list_with_none():
    assert from_key_val_list(None) is None

def test_from_key_val_list_with_invalid_string():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list('string')

def test_from_key_val_list_with_invalid_integer():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list(123)

def test_from_key_val_list_with_invalid_boolean():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list(True)

def test_from_key_val_list_with_invalid_bytes():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list(b'bytes')

def test_from_key_val_list_with_nested_tuples():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list([('key1',), ('key2', 'val2')])

def test_from_key_val_list_with_non_tuple_elements():
    with pytest.raises(ValueError, match="cannot encode objects that are not 2-tuples"):
        from_key_val_list([['key1', 'val1'], ['key2', 'val2']])

