import pytest
import cookielib
from your_module import YourClass  # Replace with the actual module and class name

@pytest.fixture
def prepared_request():
    return YourClass()  # Initialize your class here

def test_prepare_cookies_with_cookiejar(prepared_request):
    cookie_jar = cookielib.CookieJar()
    prepared_request.prepare_cookies(cookie_jar)
    assert prepared_request._cookies == cookie_jar
    assert "Cookie" in prepared_request.headers

def test_prepare_cookies_with_dict(prepared_request):
    cookies_dict = {'session_id': 'abc123', 'user_id': 'user42'}
    prepared_request.prepare_cookies(cookies_dict)
    assert isinstance(prepared_request._cookies, cookielib.CookieJar)
    assert "Cookie" in prepared_request.headers

def test_prepare_cookies_empty_dict(prepared_request):
    cookies_dict = {}
    prepared_request.prepare_cookies(cookies_dict)
    assert isinstance(prepared_request._cookies, cookielib.CookieJar)
    assert "Cookie" not in prepared_request.headers

def test_prepare_cookies_multiple_calls(prepared_request):
    cookies_dict = {'session_id': 'abc123'}
    prepared_request.prepare_cookies(cookies_dict)
    initial_header = prepared_request.headers["Cookie"]

    # Call prepare_cookies again with a different cookie
    new_cookies_dict = {'session_id': 'xyz789'}
    prepared_request.prepare_cookies(new_cookies_dict)

    # Ensure the header has not changed
    assert prepared_request.headers["Cookie"] == initial_header

def test_prepare_cookies_with_invalid_type(prepared_request):
    with pytest.raises(TypeError):
        prepared_request.prepare_cookies(123)  # Invalid type

def test_prepare_cookies_with_none(prepared_request):
    prepared_request.prepare_cookies(None)
    assert isinstance(prepared_request._cookies, cookielib.CookieJar)
    assert "Cookie" not in prepared_request.headers

def test_prepare_cookies_removing_header(prepared_request):
    cookies_dict = {'session_id': 'abc123'}
    prepared_request.prepare_cookies(cookies_dict)
    assert "Cookie" in prepared_request.headers

    # Remove the header
    del prepared_request.headers["Cookie"]
    prepared_request.prepare_cookies(cookies_dict)
    assert prepared_request.headers["Cookie"] == "session_id=abc123"

