import pytest
from collections import Mapping

# Assuming the class containing the _format_timeframe method is named TimeFrameFormatter
class TimeFrameFormatter:
    def __init__(self):
        self.timeframes = {
            'day': '{0} days',
            'hour': '{0} hours',
            'minute': '{0} minutes',
            'second': '{0} seconds',
            'week': {'plural': '{0} weeks', 'dual': '{0} week'},
            'month': {'plural': '{0} months', 'dual': '{0} month'},
            'year': {'plural': '{0} years', 'dual': '{0} year'},
        }

    def _format_timeframe(self, timeframe: str, delta: int) -> str:
        form = self.timeframes[timeframe]
        delta = abs(delta)
        if isinstance(form, Mapping):
            if delta == 2:
                form = form["dual"]
            else:
                form = form["plural"]

        return form.format(delta)

