import pytest

class TestPeek:
    class MockIterator:
        def __init__(self, items):
            self.items = items
            self.index = 0

        def __iter__(self):
            return self

        def __next__(self):
            if self.index < len(self.items):
                item = self.items[self.index]
                self.index += 1
                return item
            raise StopIteration

    class Peekable:
        _marker = object()

        def __init__(self, iterator):
            self._it = iterator
            self._cache = []

        def peek(self, default=_marker):
            if not self._cache:
                try:
                    self._cache.append(next(self._it))
                except StopIteration:
                    if default is self._marker:
                        raise
                    return default
            return self._cache[0]

    def test_peek_normal_case(self):
        it = self.MockIterator([1, 2, 3])
        peekable = self.Peekable(it)
        assert peekable.peek() == 1
        assert peekable.peek() == 1  # Should still return the same value

    def test_peek_after_next(self):
        it = self.MockIterator([1, 2, 3])
        peekable = self.Peekable(it)
        peekable.peek()
        next(peekable._it)  # Consume the first item
        assert peekable.peek() == 2

    def test_peek_empty_iterator_with_default(self):
        it = self.MockIterator([])
        peekable = self.Peekable(it)
        assert peekable.peek(default='default') == 'default'

    def test_peek_empty_iterator_without_default(self):
        it = self.MockIterator([])
        peekable = self.Peekable(it)
        with pytest.raises(StopIteration):
            peekable.peek()

    def test_peek_multiple_calls(self):
        it = self.MockIterator([1, 2, 3])
        peekable = self.Peekable(it)
        assert peekable.peek() == 1
        assert peekable.peek() == 1
        next(peekable._it)  # Consume the first item
        assert peekable.peek() == 2

    def test_peek_after_exhaustion(self):
        it = self.MockIterator([1])
        peekable = self.Peekable(it)
        assert peekable.peek() == 1
        next(peekable._it)  # Exhaust the iterator
        with pytest.raises(StopIteration):
            peekable.peek()

    def test_peek_with_custom_default(self):
        it = self.MockIterator([])
        peekable = self.Peekable(it)
        assert peekable.peek(default='custom_default') == 'custom_default'

    def test_peek_with_none_default(self):
        it = self.MockIterator([])
        peekable = self.Peekable(it)
        assert peekable.peek(default=None) is None

