import pytest

# Assuming scalar_types is defined somewhere in the module
scalar_types = (int, float, complex, bool, str, bytes)

def is_scalar(obj):
    if scalar_types and isinstance(obj, scalar_types):
        return True
    try:
        iter(obj)
    except TypeError:
        return True
    else:
        return False

def test_is_scalar_with_integers():
    assert is_scalar(5) is True
    assert is_scalar(-10) is True

def test_is_scalar_with_floats():
    assert is_scalar(3.14) is True
    assert is_scalar(-0.001) is True

def test_is_scalar_with_complex_numbers():
    assert is_scalar(1 + 2j) is True
    assert is_scalar(-3j) is True

def test_is_scalar_with_booleans():
    assert is_scalar(True) is True
    assert is_scalar(False) is True

def test_is_scalar_with_strings():
    assert is_scalar("hello") is True
    assert is_scalar("") is True

def test_is_scalar_with_bytes():
    assert is_scalar(b'bytes') is True
    assert is_scalar(b'') is True

def test_is_scalar_with_non_scalar_iterables():
    assert is_scalar([1, 2, 3]) is False
    assert is_scalar((1, 2, 3)) is False
    assert is_scalar({1, 2, 3}) is False
    assert is_scalar({'a': 1, 'b': 2}) is False
    assert is_scalar(range(5)) is False

def test_is_scalar_with_none():
    assert is_scalar(None) is True

def test_is_scalar_with_custom_objects():
    class CustomObject:
        pass

    assert is_scalar(CustomObject()) is True

def test_is_scalar_with_functions():
    def sample_function():
        pass

    assert is_scalar(sample_function) is True

def test_is_scalar_with_generator():
    def sample_generator():
        yield 1

    assert is_scalar(sample_generator()) is False

def test_is_scalar_with_bytes_array():
    assert is_scalar(bytearray(b'hello')) is True

def test_is_scalar_with_memoryview():
    assert is_scalar(memoryview(b'hello')) is True

def test_is_scalar_with_empty_iterables():
    assert is_scalar([]) is False
    assert is_scalar(()) is False
    assert is_scalar({}) is False

def test_is_scalar_with_nested_iterables():
    assert is_scalar([[1, 2], [3, 4]]) is False
    assert is_scalar(((1, 2), (3, 4))) is False

